149	/// Read BURS_TINCTURE from the station file resolved via BURD_STATION_FILE.
150	/// BURS validation upstream (zburs_enforce) guarantees the value is 1-3 chars
151	/// of lowercase alphanumeric starting with a letter.
152	pub(crate) fn rbtdrp_burs_tincture() -> Result<String, String> {
153	    let path_str = std::env::var(RBTDRP_ENV_STATION_FILE)
154	        .map_err(|_| format!("{} not set in environment", RBTDRP_ENV_STATION_FILE))?;
155	    let path = PathBuf::from(&path_str);
156	    rbtdrp_read_env_value(&path, "BURS_TINCTURE")
157	        .ok_or_else(|| format!("BURS_TINCTURE not in {}", path.display()))
158	}
