175	// ── Probes ───────────────────────────────────────────────────
176	//
177	// rbtdrb_Probe.check is `fn() -> Result<(), String>` with no parameters,
178	// so the probe reads the project root from current_dir() — theurge always
179	// launches from the project root.
180	
181	/// Live-disqualify case probe: depot levied (RBRD_CLOUD_PREFIX +
182	/// RBRD_DEPOT_MONIKER both non-blank, RBDC kindle composes a non-empty
183	/// project_id). Established by case 2 (rbtdrp_depot_stand_up).
184	fn rbtdrp_probe_depot_levied() -> Result<(), String> {
185	    let root = std::env::current_dir()
186	        .map_err(|e| format!("cannot resolve project root: {}", e))?;
187	    let rbrd = root.join(RBTDRP_RBRD_FILE);
188	
189	    let cloud = rbtdrp_read_env_value(&rbrd, RBTDRP_FIELD_RBRD_CLOUD_PREFIX).unwrap_or_default();
190	    if cloud.is_empty() {
191	        return Err(format!(
192	            "{} blank in {} — throwaway prefixes not installed",
193	            RBTDRP_FIELD_RBRD_CLOUD_PREFIX,
194	            rbrd.display()
195	        ));
196	    }
197	
198	    let moniker = rbtdrp_read_env_value(&rbrd, RBTDRP_FIELD_RBRD_DEPOT_MONIKER).unwrap_or_default();
199	    if moniker.is_empty() {
200	        return Err(format!(
201	            "{} blank in {} — depot stand-up did not run",
202	            RBTDRP_FIELD_RBRD_DEPOT_MONIKER,
203	            rbrd.display()
204	        ));
205	    }
206	
207	    Ok(())
208	}
