210	// ── Helpers ──────────────────────────────────────────────────
211	
212	/// Read an env file and return the value for `key`, or None if the key is
213	/// absent. The bash regime files use `KEY=value` lines (unquoted); comment
214	/// and blank lines are skipped. The trailing newline is stripped from value.
215	fn rbtdrp_read_env_value(path: &Path, key: &str) -> Option<String> {
216	    let content = std::fs::read_to_string(path).ok()?;
217	    let prefix = format!("{}=", key);
218	    for line in content.lines() {
219	        let trimmed = line.trim_start();
220	        if trimmed.starts_with('#') {
221	            continue;
222	        }
223	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
224	            return Some(rest.to_string());
225	        }
226	    }
227	    None
228	}
