230	/// Resolve a path that may be absolute or relative-to-project-root.
231	fn rbtdrp_resolve(root: &Path, raw: &str) -> PathBuf {
232	    if Path::new(raw).is_absolute() {
233	        PathBuf::from(raw)
234	    } else {
235	        root.join(raw)
236	    }
237	}
