239	/// Class A — working tree clean (`git status --porcelain` empty).
240	fn rbtdrp_check_tree_clean(root: &Path, violations: &mut Vec<String>) {
241	    match Command::new("git")
242	        .args(["status", "--porcelain"])
243	        .current_dir(root)
244	        .output()
245	    {
246	        Ok(out) if out.status.success() => {
247	            let stdout = String::from_utf8_lossy(&out.stdout);
248	            let trimmed = stdout.trim();
249	            if !trimmed.is_empty() {
250	                violations.push(format!(
251	                    "working tree not clean — uncommitted changes:\n{}",
252	                    trimmed
253	                ));
254	            }
255	        }
256	        Ok(out) => violations.push(format!(
257	            "git status --porcelain failed (exit {}): {}",
258	            out.status.code().unwrap_or(-1),
259	            String::from_utf8_lossy(&out.stderr).trim()
260	        )),
261	        Err(e) => violations.push(format!("git status invocation failed: {}", e)),
262	    }
263	}
