296	/// Class C — no RBRA credential files at the four role paths.
297	fn rbtdrp_check_rbra_files(root: &Path, secrets_dir: &str, violations: &mut Vec<String>) {
298	    if secrets_dir.is_empty() {
299	        violations.push(
300	            "RBRR_SECRETS_DIR is blank — cannot resolve credential paths".to_string(),
301	        );
302	        return;
303	    }
304	    let secrets = rbtdrp_resolve(root, secrets_dir);
305	    for role in RBTDRP_RBRA_ROLES {
306	        let path = secrets.join(role).join(RBTDRP_RBRA_FILE);
307	        if path.exists() {
308	            violations.push(format!("RBRA credential present: {}", path.display()));
309	        }
310	    }
311	}
