313	/// Class D — every nameplate's RBRN_SENTRY_HALLMARK and RBRN_BOTTLE_HALLMARK
314	/// is blank.
315	fn rbtdrp_check_nameplate_hallmarks(root: &Path, violations: &mut Vec<String>) {
316	    let dot_dir = root.join(RBTDRP_DOT_DIR);
317	    let entries = match std::fs::read_dir(&dot_dir) {
318	        Ok(e) => e,
319	        Err(e) => {
320	            violations.push(format!("cannot read {}: {}", dot_dir.display(), e));
321	            return;
322	        }
323	    };
324	    for entry in entries.flatten() {
325	        let np_dir = entry.path();
326	        if !np_dir.is_dir() {
327	            continue;
328	        }
329	        let rbrn = np_dir.join(RBTDRP_RBRN_FILE);
330	        if !rbrn.exists() {
331	            continue;
332	        }
333	        for field in RBTDRP_RBRN_BLANK_FIELDS {
334	            if let Some(value) = rbtdrp_read_env_value(&rbrn, field) {
335	                if !value.is_empty() {
336	                    violations.push(format!(
337	                        "nameplate hallmark non-blank: {}={} (in {})",
338	                        field,
339	                        value,
340	                        rbrn.display()
341	                    ));
342	                }
343	            }
344	        }
345	    }
