348	/// Class E — every vessel rbrv.env has RBRV_RELIQUARY blank and every
349	/// RBRV_IMAGE_*_ANCHOR field blank.
350	fn rbtdrp_check_vessel_depot_fields(
351	    root: &Path,
352	    vessel_dir: &str,
353	    violations: &mut Vec<String>,
354	) {
355	    if vessel_dir.is_empty() {
356	        violations.push("RBRR_VESSEL_DIR is blank — cannot scan vessels".to_string());
357	        return;
358	    }
359	    let vroot = rbtdrp_resolve(root, vessel_dir);
360	    let entries = match std::fs::read_dir(&vroot) {
361	        Ok(e) => e,
362	        Err(e) => {
363	            violations.push(format!("cannot read {}: {}", vroot.display(), e));
364	            return;
365	        }
366	    };
367	    for entry in entries.flatten() {
368	        let v_dir = entry.path();
369	        if !v_dir.is_dir() {
370	            continue;
371	        }
372	        let rbrv = v_dir.join(RBTDRP_RBRV_FILE);
373	        if !rbrv.exists() {
374	            continue;
375	        }
376	        rbtdrp_scan_rbrv_file(&rbrv, violations);
377	    }
378	}
379	
380	/// Scan a single rbrv.env for non-blank RBRV_RELIQUARY and RBRV_IMAGE_*_ANCHOR
381	/// fields.
382	fn rbtdrp_scan_rbrv_file(rbrv: &Path, violations: &mut Vec<String>) {
383	    let content = match std::fs::read_to_string(rbrv) {
384	        Ok(c) => c,
385	        Err(e) => {
386	            violations.push(format!("cannot read {}: {}", rbrv.display(), e));
387	            return;
388	        }
389	    };
390	    for line in content.lines() {
391	        let trimmed = line.trim_start();
392	        if trimmed.starts_with('#') {
393	            continue;
394	        }
395	        let (key, value) = match trimmed.split_once('=') {
396	            Some(kv) => kv,
397	            None => continue,
398	        };
399	        let is_reliquary = key == "RBRV_RELIQUARY";
400	        let is_anchor = key.starts_with("RBRV_IMAGE_") && key.ends_with("_ANCHOR");
401	        if (is_reliquary || is_anchor) && !value.is_empty() {
402	            violations.push(format!(
403	                "vessel depot-scoped field non-blank: {}={} (in {})",
404	                key,
405	                value,
406	                rbrv.display()
407	            ));
408	        }
409	    }
410	}
