412	// ── Env-file rewrite + git commit helpers ────────────────────
413	
414	/// Rewrite each line in `content` whose key matches an entry in `pairs`
415	/// (matched as `KEY=`) to `KEY=value`. Lines whose keys are not in `pairs`
416	/// pass through unchanged. The trailing-newline shape is preserved.
417	fn rbtdrp_replace_env_fields(content: &str, pairs: &[(&str, &str)]) -> String {
418	    let mut result: String = content
419	        .lines()
420	        .map(|line| {
421	            for (key, value) in pairs {
422	                let assign = format!("{}=", key);
423	                if line.starts_with(&assign) {
424	                    return format!("{}{}", assign, value);
425	                }
426	            }
427	            line.to_string()
428	        })
429	        .collect::<Vec<_>>()
430	        .join("\n");
431	    if content.ends_with('\n') {
432	        result.push('\n');
433	    }
434	    result
435	}
436	
437	/// `git add <file> && git commit -m <message>` from `root`. Bubbles the
438	/// underlying stderr on either step's failure.
439	fn rbtdrp_git_add_and_commit(root: &Path, file: &str, message: &str) -> Result<(), String> {
440	    rbtdrp_git_add_and_commit_paths(root, &[file], message)
441	}
442	
443	fn rbtdrp_git_add_and_commit_paths(
444	    root: &Path,
445	    files: &[&str],
446	    message: &str,
447	) -> Result<(), String> {
448	    let mut add_args: Vec<&str> = vec!["add"];
449	    add_args.extend_from_slice(files);
450	    let add = Command::new("git")
451	        .args(&add_args)
452	        .current_dir(root)
453	        .output()
454	        .map_err(|e| format!("rbtdrp: git add invocation failed: {}", e))?;
455	    if !add.status.success() {
456	        return Err(format!(
457	            "rbtdrp: git add failed (exit {}): {}",
458	            add.status.code().unwrap_or(-1),
459	            String::from_utf8_lossy(&add.stderr).trim()
460	        ));
461	    }
462	
463	    let commit = Command::new("git")
464	        .args(["commit", "-m", message])
465	        .current_dir(root)
466	        .output()
467	        .map_err(|e| format!("rbtdrp: git commit invocation failed: {}", e))?;
468	    if !commit.status.success() {
469	        return Err(format!(
470	            "rbtdrp: git commit failed (exit {}): {}",
471	            commit.status.code().unwrap_or(-1),
472	            String::from_utf8_lossy(&commit.stderr).trim()
473	        ));
474	    }
475	
476	    Ok(())
477	}
478	
479	// ── Throwaway-prefix install ─────────────────────────────────
480	
481	/// Idempotently install throwaway RBRR prefixes into `rbmm_moorings/rbrr.env`.
482	///
483	/// Pristine-lifecycle cases that need non-blank prefixes (depot/governor/
484	/// retriever/director lifecycle) call this as their first step. The helper
485	/// reads current values; if `RBRD_CLOUD_PREFIX` and `RBRR_RUNTIME_PREFIX`
486	/// already match the throwaway markers, returns `Ok(())` with no side
487	/// effect. Otherwise rewrites both lines in place, then `git add` +
488	/// `git commit` the change. One commit per fixture run regardless of which
489	/// case is the first to call it.
490	///
491	/// HEAD walks off marshal-zero after the commit; recovery is `rbw-MZ`,
492	/// matching the pristine fixture's start-over-from-zero failure mode.
493	pub(crate) fn rbtdrp_install_throwaway_prefixes(root: &Path) -> Result<(), String> {
494	    let rbrr = root.join(RBTDRP_RBRR_FILE);
495	    let rbrd = root.join(RBTDRP_RBRD_FILE);
496	    let tincture = rbtdrp_burs_tincture()?;
497	    let cloud_target = rbtdrp_throwaway_cloud_prefix(&tincture);
498	    let runtime_target = rbtdrp_throwaway_runtime_prefix(&tincture);
499	
500	    let cloud = rbtdrp_read_env_value(&rbrd, RBTDRP_FIELD_RBRD_CLOUD_PREFIX).unwrap_or_default();
501	    let runtime =
502	        rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
503	
504	    if cloud == cloud_target && runtime == runtime_target {
505	        return Ok(());
506	    }
507	
508	    if cloud != cloud_target {
509	        let content = std::fs::read_to_string(&rbrd)
510	            .map_err(|e| format!("rbtdrp: read {}: {}", rbrd.display(), e))?;
511	        let new_content = rbtdrp_replace_env_fields(
512	            &content,
513	            &[(RBTDRP_FIELD_RBRD_CLOUD_PREFIX, cloud_target.as_str())],
514	        );
515	        std::fs::write(&rbrd, &new_content)
516	            .map_err(|e| format!("rbtdrp: write {}: {}", rbrd.display(), e))?;
517	    }
518	
519	    if runtime != runtime_target {
520	        let content = std::fs::read_to_string(&rbrr)
521	            .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
522	        let new_content = rbtdrp_replace_env_fields(
523	            &content,
524	            &[(RBTDRP_FIELD_RBRR_RUNTIME_PREFIX, runtime_target.as_str())],
525	        );
526	        std::fs::write(&rbrr, &new_content)
527	            .map_err(|e| format!("rbtdrp: write {}: {}", rbrr.display(), e))?;
528	    }
529	
530	    let commit_msg = format!(
531	        "pristine-lifecycle fixture: install throwaway prefixes ({}/{})",
532	        cloud_target, runtime_target
533	    );
534	    rbtdrp_git_add_and_commit_paths(root, &[RBTDRP_RBRR_FILE, RBTDRP_RBRD_FILE], &commit_msg)
535	}
