537	/// Pick the next free moniker for `family_stem` by walking the depot_list
538	/// invocation's BURV output dir for `<family>NNNNNN.depot` files under the
539	/// current cloud_prefix subdir, parsing the numeric suffix from each, and
540	/// returning `<family><max + 1>`. Returns
541	/// `<family>RBTDRP_FAMILY_NUMERIC_FLOOR` when no matching files exist or the
542	/// output dir is missing (first run, no prior depots). Restricting the walk
543	/// to the current cloud_prefix is what makes allocation collision-safe: a
544	/// same-numbered moniker under a foreign cloud_prefix is correctly ignored.
545	fn rbtdrp_pick_next_moniker(
546	    list_result: &crate::rbtdri_invocation::rbtdri_InvokeResult,
547	    root: &Path,
548	    family_stem: &str,
549	) -> Result<String, String> {
550	    let prefix_dir = rbtdrp_cloud_prefix_subdir(root)?;
551	    let dir = list_result
552	        .burv_output
553	        .join(crate::rbtdri_invocation::RBTDRI_BURV_OUTPUT_SUBDIR)
554	        .join(&prefix_dir);
555	
556	    let entries = match std::fs::read_dir(&dir) {
557	        Ok(e) => e,
558	        Err(_) => {
559	            return Ok(format!("{}{}", family_stem, RBTDRP_FAMILY_NUMERIC_FLOOR));
560	        }
561	    };
562	
563	    let suffix_ext = format!(".{}", RBTDRP_FACT_EXT_DEPOT);
564	    let mut max_suffix: Option<u32> = None;
565	    for entry in entries.flatten() {
566	        let name = match entry.file_name().into_string() {
567	            Ok(n) => n,
568	            Err(_) => continue,
569	        };
570	        let stem = match name.strip_suffix(&suffix_ext) {
571	            Some(s) => s,
572	            None => continue,
573	        };
574	        let numeric = match stem.strip_prefix(family_stem) {
575	            Some(s) => s,
576	            None => continue,
577	        };
578	        if numeric.len() != RBTDRP_FAMILY_NUMERIC_WIDTH {
579	            continue;
580	        }
581	        let parsed: u32 = match numeric.parse() {
582	            Ok(n) => n,
583	            Err(_) => continue,
584	        };
585	        max_suffix = Some(max_suffix.map_or(parsed, |m| m.max(parsed)));
586	    }
587	
588	    let next = match max_suffix {
589	        Some(m) => m + 1,
590	        None => RBTDRP_FAMILY_NUMERIC_FLOOR,
591	    };
592	    Ok(format!("{}{}", family_stem, next))
593	}
