595	/// Compose the depot project_id from kindled regime values. Mirrors RBDC's
596	/// derivation: `${RBRD_CLOUD_PREFIX}d-${moniker}`. Used by cases 2 and 3 to
597	/// recover the project_id post-levy without re-reading a fact file (the
598	/// pre-collapse `rbgp_fact_depot_project_id` producer is gone).
599	fn rbtdrp_compose_project_id(root: &Path, moniker: &str) -> Result<String, String> {
