642	/// Case 1 — marshal-zero attestation. Aggregates all five violation classes
643	/// into a single diagnostic. A passing run is the proof that `rbw-MZ` was
644	/// just executed and committed.
645	fn rbtdrp_marshal_zero_attestation(_dir: &Path) -> rbtdre_Verdict {
646	    let root = match std::env::current_dir() {
647	        Ok(r) => r,
648	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot resolve project root: {}", e)),
649	    };
650	
651	    let rbrr = root.join(RBTDRP_RBRR_FILE);
652	    if !rbrr.exists() {
653	        return rbtdre_Verdict::Fail(format!("RBRR file not found: {}", rbrr.display()));
654	    }
655	    let rbrd = root.join(RBTDRP_RBRD_FILE);
656	    if !rbrd.exists() {
657	        return rbtdre_Verdict::Fail(format!("RBRD file not found: {}", rbrd.display()));
658	    }
659	
660	    let secrets_dir = rbtdrp_read_env_value(&rbrr, "RBRR_SECRETS_DIR").unwrap_or_default();
661	    let vessel_dir = rbtdrp_read_env_value(&rbrr, "RBRR_VESSEL_DIR").unwrap_or_default();
662	
663	    let mut violations: Vec<String> = Vec::new();
664	
665	    rbtdrp_check_tree_clean(&root, &mut violations);
666	    rbtdrp_check_rbrr_fields(&rbrr, &mut violations);
667	    rbtdrp_check_rbrd_fields(&rbrd, &mut violations);
668	    rbtdrp_check_rbra_files(&root, &secrets_dir, &mut violations);
669	    rbtdrp_check_nameplate_hallmarks(&root, &mut violations);
670	    rbtdrp_check_vessel_depot_fields(&root, &vessel_dir, &mut violations);
671	
672	    if violations.is_empty() {
673	        return rbtdre_Verdict::Pass;
674	    }
675	
676	    let body = violations
677	        .iter()
678	        .map(|v| format!("  - {}", v))
679	        .collect::<Vec<_>>()
680	        .join("\n");
681	    rbtdre_Verdict::Fail(format!(
682	        "marshal-zero attestation failed — {} violation(s):\n{}\n\n\
683	         remedy: tt/rbw-MZ.MarshalZeroes.sh, then commit and rerun.",
684	        violations.len(),
685	        body
686	    ))
687	}
