691	/// Wrapper invocation: call `rbtdri_invoke_global` and tee stdout/stderr to
692	/// `dir/<label>-stdout.txt` / `dir/<label>-stderr.txt` for diagnostic review.
693	/// Returns `Ok(InvokeResult)` regardless of exit code; callers decide what
694	/// counts as failure.
695	fn rbtdrp_invoke_logged(
696	    ctx: &mut rbtdri_Context,
697	    colophon: &str,
698	    args: &[&str],
699	    extra_env: &[(&str, &str)],
700	    dir: &Path,
701	    label: &str,
702	) -> Result<crate::rbtdri_invocation::rbtdri_InvokeResult, String> {
703	    let result = rbtdri_invoke_global(ctx, colophon, args, extra_env)?;
704	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &result.stdout);
705	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &result.stderr);
706	    Ok(result)
707	}
