709	/// Resolve the canonical RBRA path for a role by reading RBRR_SECRETS_DIR
710	/// from rbrr.env and joining `<role>/rbra.env`.
711	fn rbtdrp_canonical_rbra(root: &Path, role: &str) -> Result<PathBuf, String> {
712	    let rbrr = root.join(RBTDRP_RBRR_FILE);
713	    let secrets_dir = rbtdrp_read_env_value(&rbrr, "RBRR_SECRETS_DIR")
714	        .ok_or_else(|| format!("RBRR_SECRETS_DIR missing from {}", rbrr.display()))?;
715	    if secrets_dir.is_empty() {
716	        return Err(format!("RBRR_SECRETS_DIR is blank in {}", rbrr.display()));
717	    }
718	    Ok(rbtdrp_resolve(root, &secrets_dir).join(role).join(RBTDRP_RBRA_FILE))
719	}
