721	// ── Case 2: depot stand-up ───────────────────────────────────
722	
723	/// Case 2 — depot stand-up. Installs throwaway prefixes, picks the next free
724	/// moniker in the `pristl` family, levies the depot, re-lists to refresh
725	/// facts, reads project_id from the `<moniker>.depot-project` fact file, and
726	/// cross-checks it against the RBDC compose derivation. The moniker survives
727	/// in rbrd.env for cases 3 and 4.
728	fn rbtdrp_depot_stand_up(dir: &Path) -> rbtdre_Verdict {
729	    rbtdrc_with_ctx(|ctx| rbtdrp_depot_stand_up_impl(ctx, dir))
730	}
731	
732	fn rbtdrp_depot_stand_up_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
733	    let root = ctx.project_root().to_path_buf();
734	
735	    if let Err(e) = rbtdrp_install_throwaway_prefixes(&root) {
736	        return rbtdre_Verdict::Fail(format!("install throwaway prefixes: {}", e));
737	    }
738	
739	    let list_pre = match rbtdrp_invoke_logged(
740	        ctx,
741	        RBTDRM_COLOPHON_DEPOT_LIST,
742	        &[],
743	        &[],
744	        dir,
745	        "list-pre",
746	    ) {
747	        Ok(r) => r,
748	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (pre-levy): {}", e)),
749	    };
750	    if list_pre.exit_code != 0 {
751	        return rbtdre_Verdict::Fail(format!(
752	            "depot list (pre-levy) exit {}\n{}",
753	            list_pre.exit_code, list_pre.stderr
754	        ));
755	    }
756	
757	    let tincture = match rbtdrp_burs_tincture() {
758	        Ok(t) => t,
759	        Err(e) => return rbtdre_Verdict::Fail(format!("read BURS_TINCTURE: {}", e)),
760	    };
761	    let family_stem = rbtdrp_family_stem_arc(&tincture);
762	    let moniker = match rbtdrp_pick_next_moniker(&list_pre, &root, &family_stem) {
763	        Ok(m) => m,
764	        Err(e) => return rbtdre_Verdict::Fail(format!("pick next moniker: {}", e)),
765	    };
766	    if let Err(e) = rbtdrp_install_depot_moniker(&root, &moniker) {
767	        return rbtdre_Verdict::Fail(format!("install depot moniker: {}", e));
768	    }
769	
770	    let levy = match rbtdrp_invoke_logged(
771	        ctx,
772	        RBTDRM_COLOPHON_DEPOT_LEVY,
773	        &[],
774	        &[],
775	        dir,
776	        "levy",
777	    ) {
778	        Ok(r) => r,
779	        Err(e) => return rbtdre_Verdict::Fail(format!("depot levy: {}", e)),
780	    };
781	    if levy.exit_code != 0 {
782	        return rbtdre_Verdict::Fail(format!(
783	            "depot levy exit {}\n{}",
784	            levy.exit_code, levy.stderr
785	        ));
786	    }
787	
788	    let list_present = match rbtdrp_invoke_logged(
789	        ctx,
790	        RBTDRM_COLOPHON_DEPOT_LIST,
791	        &[],
792	        &[],
793	        dir,
794	        "list-present",
795	    ) {
796	        Ok(r) => r,
797	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after levy): {}", e)),
798	    };
799	    if list_present.exit_code != 0 {
800	        return rbtdre_Verdict::Fail(format!(
801	            "depot list (after levy) exit {}\n{}",
802	            list_present.exit_code, list_present.stderr
803	        ));
804	    }
805	
806	    let prefix_dir = match rbtdrp_cloud_prefix_subdir(&root) {
807	        Ok(p) => p,
808	        Err(e) => return rbtdre_Verdict::Fail(format!("resolve cloud_prefix subdir: {}", e)),
809	    };
810	    let fact_path = list_present
811	        .burv_output
812	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
813	        .join(&prefix_dir)
814	        .join(format!("{}.{}", moniker, RBTDRP_FACT_EXT_DEPOT_PROJECT));
815	    let fact_project_id = match std::fs::read_to_string(&fact_path) {
816	        Ok(s) => s.trim().to_string(),
817	        Err(e) => {
818	            return rbtdre_Verdict::Fail(format!(
819	                "read depot-project fact '{}': {}",
820	                fact_path.display(),
821	                e
822	            ))
823	        }
824	    };
825	    if fact_project_id.is_empty() {
826	        return rbtdre_Verdict::Fail(format!(
827	            "depot-project fact is empty: {}",
828	            fact_path.display()
829	        ));
830	    }
831	    let _ = std::fs::write(dir.join("project-id.txt"), &fact_project_id);
832	
833	    let composed_project_id = match rbtdrp_compose_project_id(&root, &moniker) {
834	        Ok(p) => p,
835	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
836	    };
837	    if composed_project_id != fact_project_id {
838	        return rbtdre_Verdict::Fail(format!(
839	            "project_id mismatch: RBDC compose='{}' vs depot-list fact='{}' \
840	             (RBDC kindle derivation diverged from payor creation)",
841	            composed_project_id, fact_project_id
842	        ));
843	    }
844	
845	    rbtdre_Verdict::Pass
846	}
