850	/// Case 3 — SA cycle. Pre-condition: depot stood up by case 2 (moniker in
851	/// rbrd.env). Mantles governor (RBRA lands in BURV output; copy to canonical),
852	/// then for each role: invest → copy assay → canonical → access-probe.
853	/// Divests both roles in reverse order, verifies BBAAN's
854	/// divest-deletes-production-RBRA contract via canonical-path absence checks.
855	/// Best-effort cleanup of assay file at the end.
856	fn rbtdrp_sa_cycle(dir: &Path) -> rbtdre_Verdict {
857	    rbtdrc_with_ctx(|ctx| rbtdrp_sa_cycle_impl(ctx, dir))
858	}
859	
860	fn rbtdrp_sa_cycle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
861	    let root = ctx.project_root().to_path_buf();
862	
863	    let rbrd = root.join(RBTDRP_RBRD_FILE);
864	    let moniker = match rbtdrp_read_env_value(&rbrd, RBTDRP_FIELD_RBRD_DEPOT_MONIKER) {
865	        Some(m) if !m.is_empty() => m,
866	        _ => {
867	            return rbtdre_Verdict::Fail(
868	                "case 2 (stand-up) did not run or rbrd.env is missing the moniker \
869	                 (RBRD_DEPOT_MONIKER is blank)"
870	                    .to_string(),
871	            )
872	        }
873	    };
874	    let _ = std::fs::write(dir.join("moniker.txt"), &moniker);
875	
876	    let mantle = match rbtdrp_invoke_logged(
877	        ctx,
878	        RBTDRM_COLOPHON_GOV_MANTLE,
879	        &[],
880	        &[],
881	        dir,
882	        "mantle",
883	    ) {
884	        Ok(r) => r,
885	        Err(e) => return rbtdre_Verdict::Fail(format!("governor mantle: {}", e)),
886	    };
887	    if mantle.exit_code != 0 {
888	        return rbtdre_Verdict::Fail(format!(
889	            "governor mantle exit {}\n{}",
890	            mantle.exit_code, mantle.stderr
891	        ));
892	    }
893	
894	    let governor_email = match rbtdri_read_burv_fact(&mantle, RBTDRP_FACT_GOVERNOR_SA_EMAIL) {
895	        Ok(s) => s,
896	        Err(e) => return rbtdre_Verdict::Fail(format!("read governor SA email fact: {}", e)),
897	    };
898	    let _ = std::fs::write(dir.join("governor-sa-email.txt"), &governor_email);
899	
900	    let assay_canonical = match rbtdrp_canonical_rbra(&root, "assay") {
901	        Ok(p) => p,
902	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
903	    };
904	
905	    if !assay_canonical.exists() {
906	        return rbtdre_Verdict::Fail(format!(
907	            "assay RBRA absent after governor mantle: {}",
908	            assay_canonical.display()
909	        ));
910	    }
911	
912	    let governor_canonical = match rbtdrp_canonical_rbra(&root, RBTDRM_ROLE_GOVERNOR) {
913	        Ok(p) => p,
914	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical governor RBRA path: {}", e)),
915	    };
916	    if let Some(parent) = governor_canonical.parent() {
917	        if let Err(e) = std::fs::create_dir_all(parent) {
918	            return rbtdre_Verdict::Fail(format!(
919	                "create governor RBRA dir {}: {}",
920	                parent.display(),
921	                e
922	            ));
923	        }
924	    }
925	    if let Err(e) = std::fs::copy(&assay_canonical, &governor_canonical) {
926	        return rbtdre_Verdict::Fail(format!(
927	            "copy assay RBRA → governor canonical {}: {}",
928	            governor_canonical.display(),
929	            e
930	        ));
931	    }
932	
933	    // Retriever: invest → assay → canonical → access-probe.
934	    let invest_ret = match rbtdrp_invoke_logged(
935	        ctx,
936	        RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
937	        &[RBTDRP_IDENTITY_RETRIEVER],
938	        &[],
939	        dir,
940	        "invest-retriever",
941	    ) {
942	        Ok(r) => r,
943	        Err(e) => return rbtdre_Verdict::Fail(format!("invest retriever: {}", e)),
944	    };
945	    if invest_ret.exit_code != 0 {
946	        return rbtdre_Verdict::Fail(format!(
947	            "invest retriever exit {}\n{}",
948	            invest_ret.exit_code, invest_ret.stderr
949	        ));
950	    }
951	
952	    if !assay_canonical.exists() {
953	        return rbtdre_Verdict::Fail(format!(
954	            "assay RBRA absent after invest-retriever: {}",
955	            assay_canonical.display()
956	        ));
957	    }
958	
959	    let retriever_canonical = match rbtdrp_canonical_rbra(&root, RBTDRM_ROLE_RETRIEVER) {
960	        Ok(p) => p,
961	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical retriever RBRA path: {}", e)),
962	    };
963	    if let Some(parent) = retriever_canonical.parent() {
964	        if let Err(e) = std::fs::create_dir_all(parent) {
965	            return rbtdre_Verdict::Fail(format!(
966	                "create retriever RBRA dir {}: {}",
967	                parent.display(),
968	                e
969	            ));
970	        }
971	    }
972	    if let Err(e) = std::fs::copy(&assay_canonical, &retriever_canonical) {
973	        return rbtdre_Verdict::Fail(format!(
974	            "copy assay RBRA → retriever canonical {}: {}",
975	            retriever_canonical.display(),
976	            e
977	        ));
978	    }
979	
