1133	/// Case 4 (new) — live-disqualify refusal. Pre-condition: depot levied
1134	/// by case 2 (probe asserts both RBRD_CLOUD_PREFIX and RBRD_DEPOT_MONIKER
1135	/// are non-blank). Composes the live RBDC_DEPOT_PROJECT_ID and invokes
1136	/// `rbw-dU` with it as $1; expects non-zero exit + recovery diagnostic
1137	/// naming `RBRD_DEPOT_MONIKER` (BBAA9 contract). The refusal lands
1138	/// before authenticate (rbgp_Payor.sh:944-948), so no GCP traffic
1139	/// occurs — assertion is on exit-code + diagnostic shape only.
1140	fn rbtdrp_depot_live_disqualify(dir: &Path) -> rbtdre_Verdict {
1141	    let probe = rbtdrb_Probe {
1142	        name: "depot levied (RBRD_CLOUD_PREFIX + RBRD_DEPOT_MONIKER set)",
1143	        check: rbtdrp_probe_depot_levied,
1144	        remediation: "rerun case 2 (rbtdrp_depot_stand_up) before this case",
1145	    };
1146	    if let Err(v) = rbtdrb_assert(&probe) {
1147	        return v;
1148	    }
1149	    rbtdrc_with_ctx(|ctx| rbtdrp_depot_live_disqualify_impl(ctx, dir))
1150	}
