1152	fn rbtdrp_depot_live_disqualify_impl(
1153	    ctx: &mut rbtdri_Context,
1154	    dir: &Path,
1155	) -> rbtdre_Verdict {
1156	    let root = ctx.project_root().to_path_buf();
1157	
1158	    let rbrd = root.join(RBTDRP_RBRD_FILE);
1159	    let moniker = match rbtdrp_read_env_value(&rbrd, RBTDRP_FIELD_RBRD_DEPOT_MONIKER) {
1160	        Some(m) if !m.is_empty() => m,
1161	        _ => {
1162	            return rbtdre_Verdict::Fail(
1163	                "RBRD_DEPOT_MONIKER blank — probe should have caught this".to_string(),
1164	            )
1165	        }
1166	    };
1167	
1168	    let project_id = match rbtdrp_compose_project_id(&root, &moniker) {
1169	        Ok(p) => p,
1170	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
1171	    };
1172	    let _ = std::fs::write(dir.join("live-project-id.txt"), &project_id);
1173	
1174	    let result = match rbtdrp_invoke_logged(
1175	        ctx,
1176	        RBTDRM_COLOPHON_DEPOT_UNMAKE,
1177	        &[&project_id],
1178	        &[(RBTDRI_BURE_CONFIRM_KEY, RBTDRI_BURE_CONFIRM_SKIP)],
1179	        dir,
1180	        "live-disqualify",
1181	    ) {
1182	        Ok(r) => r,
1183	        Err(e) => return rbtdre_Verdict::Fail(format!("rbw-dU invocation: {}", e)),
1184	    };
1185	
1186	    if result.exit_code == 0 {
1187	        return rbtdre_Verdict::Fail(format!(
1188	            "rbw-dU '{}' exited 0 — BBAA9 live-disqualify contract violated \
1189	             (refusal must die when target == RBDC_DEPOT_PROJECT_ID)",
1190	            project_id
1191	        ));
1192	    }
1193	
1194	    // BUW dispatch merges stderr→stdout; assertion checks combined output.
1195	    let combined = format!("{}{}", result.stdout, result.stderr);
1196	    if !combined.contains(RBTDRP_LIVE_DISQUALIFY_RECOVERY) {
1197	        return rbtdre_Verdict::Fail(format!(
1198	            "rbw-dU live-disqualify diagnostic did not name '{}' as recovery path\n\
1199	             stdout:\n{}\n\nstderr:\n{}",
1200	            RBTDRP_LIVE_DISQUALIFY_RECOVERY, result.stdout, result.stderr
1201	        ));
1202	    }
1203	
1204	    rbtdre_Verdict::Pass
1205	}
