1220	fn rbtdrp_depot_tear_down_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
1221	    let root = ctx.project_root().to_path_buf();
1222	
1223	    let rbrd = root.join(RBTDRP_RBRD_FILE);
1224	    let moniker = match rbtdrp_read_env_value(&rbrd, RBTDRP_FIELD_RBRD_DEPOT_MONIKER) {
1225	        Some(m) if !m.is_empty() => m,
1226	        _ => {
1227	            return rbtdre_Verdict::Fail(
1228	                "case 2 (stand-up) did not run or rbrd.env is missing the moniker \
1229	                 (RBRD_DEPOT_MONIKER is blank)"
1230	                    .to_string(),
1231	            )
1232	        }
1233	    };
1234	
1235	    let project_id = match rbtdrp_compose_project_id(&root, &moniker) {
1236	        Ok(p) => p,
1237	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
1238	    };
1239	    let _ = std::fs::write(dir.join("project-id.txt"), &project_id);
1240	
1241	    if let Err(e) =
1242	        rbtdrp_install_depot_moniker(&root, RBTDRP_TEAR_DOWN_PLACEHOLDER_MONIKER)
1243	    {
1244	        return rbtdre_Verdict::Fail(format!("rotate moniker before unmake: {}", e));
1245	    }
1246	
1247	    let unmake = match rbtdrp_invoke_logged(
1248	        ctx,
1249	        RBTDRM_COLOPHON_DEPOT_UNMAKE,
1250	        &[&project_id],
1251	        &[(RBTDRI_BURE_CONFIRM_KEY, RBTDRI_BURE_CONFIRM_SKIP)],
1252	        dir,
1253	        "unmake",
1254	    ) {
1255	        Ok(r) => r,
1256	        Err(e) => return rbtdre_Verdict::Fail(format!("depot unmake: {}", e)),
1257	    };
1258	    if unmake.exit_code != 0 {
1259	        return rbtdre_Verdict::Fail(format!(
1260	            "depot unmake exit {}\n{}",
1261	            unmake.exit_code, unmake.stderr
1262	        ));
1263	    }
1264	
1265	    let list_after = match rbtdrp_invoke_logged(
1266	        ctx,
1267	        RBTDRM_COLOPHON_DEPOT_LIST,
1268	        &[],
1269	        &[],
1270	        dir,
1271	        "list-after",
1272	    ) {
1273	        Ok(r) => r,
1274	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after unmake): {}", e)),
1275	    };
1276	    if list_after.exit_code != 0 {
1277	        return rbtdre_Verdict::Fail(format!(
1278	            "depot list (after unmake) exit {}\n{}",
1279	            list_after.exit_code, list_after.stderr
1280	        ));
1281	    }
1282	
1283	    let prefix_dir = match rbtdrp_cloud_prefix_subdir(&root) {
1284	        Ok(p) => p,
1285	        Err(e) => return rbtdre_Verdict::Fail(format!("resolve cloud_prefix subdir: {}", e)),
1286	    };
1287	    let depot_fact_path = list_after
1288	        .burv_output
1289	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
1290	        .join(&prefix_dir)
1291	        .join(format!("{}.{}", moniker, RBTDRP_FACT_EXT_DEPOT));
1292	
1293	    if !depot_fact_path.exists() {
1294	        return rbtdre_Verdict::Pass;
1295	    }
1296	
1297	    let depot_state = match std::fs::read_to_string(&depot_fact_path) {
1298	        Ok(s) => s.trim().to_string(),
1299	        Err(e) => {
1300	            return rbtdre_Verdict::Fail(format!(
1301	                "read depot fact '{}': {}",
1302	                depot_fact_path.display(),
1303	                e
1304	            ))
1305	        }
1306	    };
1307	
1308	    if depot_state == RBTDRP_DELETE_REQUESTED {
1309	        return rbtdre_Verdict::Pass;
1310	    }
1311	
1312	    rbtdre_Verdict::Fail(format!(
1313	        "depot '{}' (project '{}') still present with unexpected state '{}' after unmake \
1314	         (expected absent or '{}')",
1315	        moniker, project_id, depot_state, RBTDRP_DELETE_REQUESTED
