48	fn main() -> ExitCode {
49	    let args: Vec<String> = std::env::args().collect();
50	
51	    if args.get(1).map(|s| s.as_str()) == Some("single") {
52	        return rbtdb_run_single(&args[2..]);
53	    }
54	
55	    rbtdb_run_suite(&args[1..])
56	}
