58	fn rbtdb_read_dispatch_dir(name: &str) -> Result<PathBuf, String> {
59	    match std::env::var(name) {
60	        Ok(v) if !v.is_empty() => rbtdrx_posix_to_native(&v),
61	        _ => Err(format!(
62	            "rbtd: {} is not set — theurge must be launched via BUK tabtarget",
63	            name
64	        )),
65	    }
66	}
