68	struct rbtdb_Roots {
69	    trace_root: PathBuf,
70	    burv_temp_root: PathBuf,
71	    burv_output_root: PathBuf,
72	}
73	
74	fn rbtdb_allocate_roots() -> Result<rbtdb_Roots, String> {
75	    let burd_temp = rbtdb_read_dispatch_dir(RBTDRI_BURD_TEMP_DIR_KEY)?;
76	    let burd_output = rbtdb_read_dispatch_dir(RBTDRI_BURD_OUTPUT_DIR_KEY)?;
77	
78	    let trace_root = burd_temp.join("rbtd");
79	    let burv_temp_root = trace_root.join("burv");
80	    let burv_output_root = burd_output.join("rbtd").join("burv");
81	
82	    std::fs::create_dir_all(&trace_root)
83	        .map_err(|e| format!("rbtd: failed to create trace root '{}': {}", trace_root.display(), e))?;
84	    std::fs::create_dir_all(&burv_temp_root)
85	        .map_err(|e| format!("rbtd: failed to create burv temp root '{}': {}", burv_temp_root.display(), e))?;
86	    std::fs::create_dir_all(&burv_output_root)
87	        .map_err(|e| format!("rbtd: failed to create burv output root '{}': {}", burv_output_root.display(), e))?;
88	
89	    Ok(rbtdb_Roots { trace_root, burv_temp_root, burv_output_root })
90	}
91	
92	// ── Suite runner ─────────────────────────────────────────────
93	
94	fn rbtdb_run_suite(args: &[String]) -> ExitCode {
95	    let manifest = match args.first() {
96	        Some(m) => m,
97	        None => rbtd::rbtdrg_fatal_now!(
98	            "rbtd: usage: rbtd <manifest> <fixture>\n\
99	             theurge must be launched via tabtarget (e.g. tt/rbtd-r.FixtureRun.tadmor.sh)"
100	        ),
101	    };
102	
103	    let fixture = match args.get(1) {
104	        Some(n) => n,
105	        None => rbtd::rbtdrg_fatal_now!("rbtd: no fixture argument — which test fixture to run?"),
106	    };
107	
108	    if let Err(msg) = rbtdrm_verify(manifest, fixture) {
109	        rbtd::rbtdrg_fatal_now!("{}", msg);
110	    }
111	
112	    let project_root = match std::env::current_dir() {
113	        Ok(p) => p,
114	        Err(e) => rbtd::rbtdrg_fatal_now!("rbtd: cannot determine working directory: {}", e),
115	    };
116	
117	    let roots = match rbtdb_allocate_roots() {
118	        Ok(r) => r,
119	        Err(msg) => rbtd::rbtdrg_fatal_now!("{}", msg),
120	    };
121	
122	    let ctx = rbtdri_Context::new(
123	        &project_root,
124	        fixture,
125	        &roots.burv_temp_root,
126	        &roots.burv_output_root,
127	    );
128	
129	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
130	        Some(f) => f,
131	        None => rbtd::rbtdrg_fatal_now!(
132	            "rbtd: fixture '{}' has no registered Fixture — \
133	             manifest verification accepted the name but no Fixture static is bound. \
134	             Update rbtdrc_lookup_fixture in rbtdrc_crucible.rs.",
135	            fixture
136	        ),
137	    };
138	
139	    rbtdrc_set_context(ctx);
140	
141	    let colors = rbtdre_detect_colors();
142	    let run_result = rbtdre_run_fixture(fixture_def, &colors, &roots.trace_root);
143	
144	    let _ctx = rbtdrc_take_context();
145	
146	    let result = match run_result {
147	        Ok(r) => r,
148	        Err(msg) => rbtd::rbtdrg_fatal_now!("rbtd: {}", msg),
149	    };
150	
151	    rbtdre_print_summary(&result, &colors);
152	
153	    if result.failed > 0 {
154	        rbtd::rbtdrg_error_now!("rbtd: {} case(s) failed", result.failed);
155	        ExitCode::FAILURE
156	    } else {
157	        ExitCode::SUCCESS
158	    }
159	}
160	
161	// ── Single-case runner ───────────────────────────────────────
162	
163	fn rbtdb_run_single(args: &[String]) -> ExitCode {
164	    let manifest = match args.first() {
165	        Some(m) => m,
166	        None => rbtd::rbtdrg_fatal_now!(
167	            "rbtd single: usage: rbtd single <manifest> <fixture> [case]\n\
168	             omit case to list all cases for the fixture"
169	        ),
170	    };
171	
172	    let fixture = match args.get(1) {
173	        Some(f) => f,
174	        None => {
175	            rbtd::rbtdrg_error_now!("rbtd single: no fixture argument");
176	            rbtdb_list_fixtures();
177	            return ExitCode::FAILURE;
178	        }
179	    };
180	
181	    if !RBTDRC_FIXTURES.iter().any(|f| f.name == *fixture) {
182	        rbtd::rbtdrg_error_now!("rbtd single: unknown fixture '{}'", fixture);
183	        rbtdb_list_fixtures();
184	        return ExitCode::FAILURE;
185	    }
186	
187	    if let Err(msg) = rbtdrm_verify(manifest, fixture) {
188	        rbtd::rbtdrg_fatal_now!("{}", msg);
189	    }
190	
191	    // Set up execution context early — needed for charge check and case execution
192	    let project_root = match std::env::current_dir() {
193	        Ok(p) => p,
194	        Err(e) => rbtd::rbtdrg_fatal_now!("rbtd: cannot determine working directory: {}", e),
195	    };
196	
197	    let roots = match rbtdb_allocate_roots() {
198	        Ok(r) => r,
199	        Err(msg) => rbtd::rbtdrg_fatal_now!("{}", msg),
200	    };
201	
202	    // Context is required for every case execution path (rbtdrc_with_ctx).
203	    // Fixtures with a setup hook (crucible charge) additionally verify their
204	    // crucible is charged externally — single-case mode never charges.
205	    let mut ctx = rbtdri_Context::new(
206	        &project_root,
207	        fixture,
208	        &roots.burv_temp_root,
209	        &roots.burv_output_root,
210	    );
211	
212	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
213	        Some(f) => f,
214	        None => rbtd::rbtdrg_fatal_now!(
215	            "rbtd single: fixture '{}' has no registered Fixture",
216	            fixture
217	        ),
218	    };
219	
220	    if fixture_def.setup.is_some() {
221	        match rbtdri_invoke_global(
222	            &mut ctx,
223	            RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
224	            &[fixture],
225	            &[],
226	        ) {
227	            Ok(r) if r.exit_code == 0 => {}
228	            _ => rbtd::rbtdrg_fatal_now!(
229	                "rbtd single: crucible not charged for '{}'\n\
230	                 charge first: tt/rbw-cC.Charge.{}.sh",
231	                fixture, fixture
232	            ),
233	        }
234	    }
235	
236	    rbtdrc_set_context(ctx);
237	
238	    let cases = fixture_def.cases;
239	
240	    // No case argument — list all cases
241	    let case_name = match args.get(2) {
242	        None => {
243	            rbtdre_list_cases(cases);
244	            return ExitCode::SUCCESS;
245	        }
246	        Some(n) => n,
247	    };
248	
249	    // Find the case
250	    let case = match rbtdre_find_case(cases, case_name) {
251	        Some(c) => c,
252	        None => {
253	            rbtd::rbtdrg_error_now!(
254	                "rbtd single: case '{}' not found in fixture '{}'",
255	                case_name, fixture
256	            );
257	            rbtdre_list_cases(cases);
258	            return ExitCode::FAILURE;
259	        }
260	    };
261	
262	    let colors = rbtdre_detect_colors();
263	    let result = match rbtdre_run_single_case(case, &colors, &roots.trace_root) {
264	        Ok(r) => r,
265	        Err(msg) => rbtd::rbtdrg_fatal_now!("rbtd: case execution error: {}", msg),
266	    };
267	
268	    rbtdre_print_summary(&result, &colors);
269	
270	    if result.failed > 0 {
271	        ExitCode::FAILURE
272	    } else {
273	        ExitCode::SUCCESS
274	    }
275	}
276	
277	fn rbtdb_list_fixtures() {
278	    rbtd::rbtdrg_info_now!("available fixtures:");
279	    for f in RBTDRC_FIXTURES {
280	        rbtd::rbtdrg_info_now!("  {}", f.name);
281	    }
282	}
